import AVFoundation
import Foundation

// MARK: - Lens Control
extension CameraSessionManager {
    func getLensList() -> [String]? {
        guard let devices = self.deviceList else { return nil }

        return devices.map { device in
            device.deviceType.rawValue
                .replacingOccurrences(
                    of: "AVCaptureDeviceTypeBuiltIn", with: ""
                )
                .replacingOccurrences(of: "Camera", with: "")
        }
    }

    func getLensIndex() -> Int? {
        if self.currentDevice == nil { return nil }
        return self.currentLensIndex
    }

    func setLensIndex(index: Int) {
        tearDownAutoExposureObserver()
        guard let devices = self.deviceList else {
            self.messageText = "Changing lens failed."
            return
        }

        self.currentLensIndex = index
        self.isSessionConfigured = false

        let clampedIndex = min(max(0, index), devices.count - 1)
        let deviceType = devices[clampedIndex].deviceType

        if configureSession(deviceType: deviceType) == 0 {
            self.messageText = "Changed lens to #\(clampedIndex)."
        } else {
            self.messageText = "Changing lens failed."
        }
    }
}

